/* wif-das-batch-interface-sql-oracle.xml - insertDasMidLocDsnWave - DAS 중분류DAS 로케이션 지정 Wave INSERT SQL */
INSERT INTO TWIF_DAS_MIDLOC_DSN_WA
(
	WASEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,WAHDDAY
	,DASEQTYPE
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,IFRETRYYN
	,IFRETRYIFID
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
)
VALUES
(
	#{waSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{waHdDay}
	,#{dasEqType}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{ifretryyn}
	,#{ifretryifid}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)

