/* wif-das-batch-interface-sql-oracle.xml - insertDasMidLocDsnMidCell - DAS 중분류DAS 로케이션 지정 Middle Cell INSERT SQL */

	SELECT nextval('seq_twif_das_midloc_dsn_midcell') AS MID_CELL_SEQ

INSERT INTO TWIF_DAS_MIDLOC_DSN_MIDCELL
(
	WASEQ
	,SMLSTNSEQ
	,MIDCELLSEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,SMLSTN
	,MIDCELLBRCD
	,ORD
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
)
VALUES
(
	#{waSeq}
	,#{smlStnSeq}
	,#{midCellSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{smlStn}
	,#{midCellBrcd}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)
